// Tournament reference data for the FIFA World Cup 2026.
// The ANNEX table encodes FIFA's official allocation of the eight best
// third-placed teams to Round-of-32 slots, keyed by the sorted set of the
// eight groups that produced a qualifying third-placed team.
// Ported verbatim from the original tracker; do not edit by hand.

export type RawTeam = [name: string, code: string, flag: string];

export interface KoRef {
  W?: string;  // winner of group
  R?: string;  // runner-up of group
  T?: string;  // third-place team allocated to this winner-group slot
  WM?: number; // winner of match number
  LM?: number; // loser of match number
}
export interface KoMatch { no: number; a: KoRef; b: KoRef; }
export interface Round { label: string; nums: number[]; }

