export const GROUP_LETTERS: string[] = Object.keys(GROUPS);

export interface Team { name: string; code: string; flag: string; group: string; idx: number; }
export const TEAMS: Record<string, Team[]> = {};
for (const g of GROUP_LETTERS) {
  TEAMS[g] = GROUPS[g].map((t, i) => ({ name: t[0], code: t[1], flag: t[2], group: g, idx: i }));
}

